import { RuleTester } from 'eslint';
import tseslint from 'typescript-eslint';
import { noNativeHttp } from "../../rules/no-native-http.js";
import { languageOptions } from "../../runtime.js";
const ruleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parserOptions: {
            ecmaVersion: 'latest',
            sourceType: 'module',
            ecmaFeatures: {
                jsx: true,
            },
        },
    },
});
// Separate tester for TypeScript code
const tsRuleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parser: tseslint.parser,
        parserOptions: {
            ecmaVersion: 'latest',
            sourceType: 'module',
        },
    },
});
describe('no-native-http', () => {
    // Main test suite with JavaScript code
    ruleTester.run('no-native-http', noNativeHttp, {
        valid: [
            {
                name: 'allows hubspot.fetch() calls',
                code: `
          function getData() {
            return hubspot.fetch('https://api.example.com');
          }
        `,
            },
            {
                name: 'allows fetch as method call on other objects',
                code: `
          const api = {
            fetch: () => 'data'
          };

          function getData() {
            return api.fetch();
          }
        `,
            },
            {
                name: 'ignores fetch mentioned in comments',
                code: `
          // Use fetch() to get data
          /* XMLHttpRequest is deprecated */
          function getData() {
            return hubspot.fetch('https://api.example.com');
          }
        `,
            },
            {
                name: 'ignores fetch mentioned in strings',
                code: `
          const message = 'You should use fetch()';
          const code = "new XMLHttpRequest()";

          function getData() {
            return hubspot.fetch('https://api.example.com');
          }
        `,
            },
            {
                name: 'allows React component with JSX',
                code: `
          import { Text } from '@hubspot/ui-extensions';

          function Component() {
            const data = hubspot.fetch('https://api.example.com');
            return <Text>Hello</Text>;
          }
        `,
            },
            {
                name: 'allows destructured fetch from hubspot',
                code: `
          const { fetch } = hubspot;

          function getData() {
            return fetch('https://api.example.com');
          }
        `,
            },
            {
                name: 'allows fetch as function parameter',
                code: `
          function processRequest(fetch) {
            return fetch('https://api.example.com');
          }
        `,
            },
            {
                name: 'allows locally declared fetch function',
                code: `
          function getData() {
            const fetch = (url) => hubspot.fetch(url);
            return fetch('https://api.example.com');
          }
        `,
            },
        ],
        invalid: [
            {
                name: 'reports error for global fetch() call',
                code: `
          function getData() {
            return fetch('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for window.fetch() call',
                code: `
          function getData() {
            return window.fetch('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for globalThis.fetch() call',
                code: `
          function getData() {
            return globalThis.fetch('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for self.fetch() call',
                code: `
          function getData() {
            return self.fetch('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for new XMLHttpRequest()',
                code: `
          function getData() {
            const xhr = new XMLHttpRequest();
            xhr.open('GET', 'https://api.example.com');
            return xhr;
          }
        `,
                errors: [
                    {
                        messageId: 'nativeXMLHttpRequest',
                    },
                ],
            },
            {
                name: 'reports error for window["fetch"]()',
                code: `
          function getData() {
            return window['fetch']('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for globalThis["fetch"]()',
                code: `
          function getData() {
            return globalThis['fetch']('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for self["fetch"]()',
                code: `
          function getData() {
            return self['fetch']('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports multiple errors for multiple fetch calls',
                code: `
          function getData() {
            fetch('https://api1.example.com');
            window.fetch('https://api2.example.com');
            globalThis.fetch('https://api3.example.com');
            self.fetch('https://api4.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                    {
                        messageId: 'nativeFetch',
                    },
                    {
                        messageId: 'nativeFetch',
                    },
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error in React component with JSX',
                code: `
          import { Text } from '@hubspot/ui-extensions';

          function Component() {
            const data = fetch('https://api.example.com');
            return <Text>Hello</Text>;
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for fetch even when imported from library',
                code: `
          import fetch from 'node-fetch';

          function getData() {
            return fetch('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for fetch in async function',
                code: `
          async function getData() {
            return await fetch('https://api.example.com');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for fetch in try/catch block',
                code: `
          function getData() {
            try {
              return fetch('https://api.example.com');
            } catch (e) {
              console.error(e);
            }
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for fetch in class method',
                code: `
          class ApiClient {
            getData() {
              return fetch('https://api.example.com');
            }
          }
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
            {
                name: 'reports error for XMLHttpRequest in class method',
                code: `
          class ApiClient {
            getData() {
              const xhr = new XMLHttpRequest();
              return xhr;
            }
          }
        `,
                errors: [
                    {
                        messageId: 'nativeXMLHttpRequest',
                    },
                ],
            },
            {
                name: 'reports error for fetch in arrow function',
                code: `
          const getData = () => fetch('https://api.example.com');
        `,
                errors: [
                    {
                        messageId: 'nativeFetch',
                    },
                ],
            },
        ],
    });
    // TypeScript-specific tests (requires TypeScript parser)
    tsRuleTester.run('no-native-http (TypeScript)', noNativeHttp, {
        valid: [
            {
                name: 'allows typeof fetch in type alias',
                code: `type FetchType = typeof fetch;`,
            },
            {
                name: 'allows typeof fetch in interface property',
                code: `
          interface ApiClient {
            request: typeof fetch;
          }
        `,
            },
            {
                name: 'allows typeof fetch in function return type',
                code: `
          function getRequestFn(): typeof fetch {
            return hubspot.fetch;
          }
        `,
            },
            {
                name: 'allows typeof XMLHttpRequest in type alias',
                code: `type XHRType = typeof XMLHttpRequest;`,
            },
            {
                name: 'allows typeof XMLHttpRequest in interface',
                code: `
          interface LegacyClient {
            xhr: typeof XMLHttpRequest;
          }
        `,
            },
        ],
        invalid: [
            {
                name: 'reports error for fetch call even after type declaration',
                code: `
          type FetchType = typeof fetch;

          function getData() {
            return fetch('https://api.example.com');
          }
        `,
                errors: [{ messageId: 'nativeFetch' }],
            },
            {
                name: 'reports error for XMLHttpRequest instantiation even after type declaration',
                code: `
          type XHRType = typeof XMLHttpRequest;

          function getData() {
            return new XMLHttpRequest();
          }
        `,
                errors: [{ messageId: 'nativeXMLHttpRequest' }],
            },
        ],
    });
    describe('scope analysis validation (isLocalVariable utility)', () => {
        describe('identifies function parameters as local variables', () => {
            // Tests: isLocalVariable returns true for function parameters
            // Validates that parameters named 'fetch' don't trigger false positives
            ruleTester.run('no-native-http', noNativeHttp, {
                valid: [
                    {
                        name: 'fetch as function parameter',
                        code: `
              function processRequest(fetch) {
                return fetch('https://api.example.com');
              }
            `,
                    },
                    {
                        name: 'XMLHttpRequest as function parameter',
                        code: `
              function processRequest(XMLHttpRequest) {
                return new XMLHttpRequest();
              }
            `,
                    },
                ],
                invalid: [],
            });
        });
        describe('identifies destructured variables as local', () => {
            // Tests: isLocalVariable returns true for destructured local variables
            // Validates that const { fetch } = hubspot pattern is correctly allowed
            ruleTester.run('no-native-http', noNativeHttp, {
                valid: [
                    {
                        name: 'destructured fetch from hubspot',
                        code: `
              const { fetch } = hubspot;

              function getData() {
                return fetch('https://api.example.com');
              }
            `,
                    },
                    {
                        name: 'destructured fetch with rename',
                        code: `
              const { fetch: customFetch } = hubspot;

              function getData() {
                return customFetch('https://api.example.com');
              }
            `,
                    },
                ],
                invalid: [],
            });
        });
        describe('identifies const/let declarations as local', () => {
            // Tests: isLocalVariable returns true for const/let declarations
            // Validates that locally declared functions don't trigger errors
            ruleTester.run('no-native-http', noNativeHttp, {
                valid: [
                    {
                        name: 'locally declared fetch function',
                        code: `
              function getData() {
                const fetch = (url) => hubspot.fetch(url);
                return fetch('https://api.example.com');
              }
            `,
                    },
                    {
                        name: 'locally declared XMLHttpRequest class',
                        code: `
              function getData() {
                const XMLHttpRequest = class {
                  constructor() {}
                };
                return new XMLHttpRequest();
              }
            `,
                    },
                ],
                invalid: [],
            });
        });
        describe('flags imports as non-local (excludes ImportBinding)', () => {
            // Tests: isLocalVariable returns false for imports (def.type === 'ImportBinding')
            // Critical for preventing false negatives with imported fetch libraries
            ruleTester.run('no-native-http', noNativeHttp, {
                valid: [],
                invalid: [
                    {
                        name: 'imported fetch from library should still error',
                        code: `
              import fetch from 'node-fetch';

              function getData() {
                return fetch('https://api.example.com');
              }
            `,
                        errors: [{ messageId: 'nativeFetch' }],
                    },
                    {
                        name: 'imported named fetch should still error',
                        code: `
              import { fetch } from 'node-fetch';

              function getData() {
                return fetch('https://api.example.com');
              }
            `,
                        errors: [{ messageId: 'nativeFetch' }],
                    },
                ],
            });
        });
        describe('identifies global fetch calls correctly', () => {
            // Tests: isLocalVariable returns false for global identifiers
            // Ensures actual native fetch() calls are caught
            ruleTester.run('no-native-http', noNativeHttp, {
                valid: [],
                invalid: [
                    {
                        name: 'global fetch call',
                        code: `
              function getData() {
                return fetch('https://api.example.com');
              }
            `,
                        errors: [{ messageId: 'nativeFetch' }],
                    },
                    {
                        name: 'global XMLHttpRequest',
                        code: `
              function getData() {
                return new XMLHttpRequest();
              }
            `,
                        errors: [{ messageId: 'nativeXMLHttpRequest' }],
                    },
                ],
            });
        });
        describe('handles scope chain traversal correctly', () => {
            // Tests: isLocalVariable walks up scope chain (scope.upper)
            // Validates behavior with nested scopes
            ruleTester.run('no-native-http', noNativeHttp, {
                valid: [
                    {
                        name: 'nested function with outer parameter',
                        code: `
              function wrapper(fetch) {
                function inner() {
                  return fetch('https://api.example.com');
                }
                return inner();
              }
            `,
                    },
                    {
                        name: 'nested arrow function with outer const',
                        code: `
              function wrapper() {
                const fetch = hubspot.fetch;
                const inner = () => fetch('https://api.example.com');
                return inner();
              }
            `,
                    },
                ],
                invalid: [
                    {
                        name: 'nested function with global fetch',
                        code: `
              function wrapper() {
                function inner() {
                  return fetch('https://api.example.com');
                }
                return inner();
              }
            `,
                        errors: [{ messageId: 'nativeFetch' }],
                    },
                ],
            });
        });
    });
});
